# --- Session Management ---

class RedisSession:
    def __init__(self, session_id=None):
        self.session_id = session_id if session_id else str(uuid.uuid4())
        self._data = {}
        self.modified = False

    def __getitem__(self, key):
        return self._data.get(key)

    def __setitem__(self, key, value):
        self._data[key] = value
        self.modified = True

    def __delitem__(self, key):
        if key in self._data:
            del self._data[key]
            self.modified = True

    def get(self, key, default=None):
        return self._data.get(key, default)

    def update(self, other=None, **kwargs):
        if other:
            self._data.update(other)
        self._data.update(kwargs)
        self.modified = True

    def pop(self, key, default=None):
        if key in self._data:
            self.modified = True
            return self._data.pop(key)
        return default

    def clear(self):
        self._data.clear()
        self.modified = True

    def load(self):
        session_data_json = redis_client.get(f"session:{self.session_id}")
        if session_data_json:
            self._data = json.loads(session_data_json)
        else:
            self._data = {}

    def save(self, expires_delta=3600):  # Session expires in 1 hour by default
        if self.modified:
            redis_client.setex(f"session:{self.session_id}", expires_delta, json.dumps(self._data))
            self.modified = False

    def delete(self):
        redis_client.delete(f"session:{self.session_id}")
        self._data = {}
        self.modified = False

@app.before_request
def load_redis_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        flask_session = RedisSession(session_id)
        flask_session.load()
    else:
        flask_session = RedisSession()
    request.flask_session = flask_session

@app.after_request
def save_redis_session(response):
    flask_session = request.flask_session
    if flask_session.modified:
        flask_session.save()
    
    # Set the session cookie if it's new or needs to be updated
    if 'session_id' not in request.cookies or request.cookies['session_id'] != flask_session.session_id:
        response.set_cookie('session_id', flask_session.session_id, httponly=True, samesite='Lax', secure=False) # Set secure=True in production
    
    return response

