# --- Caching Decorator ---

def cache(key_prefix, timeout=300):
    """
    A decorator to cache the results of a function in Redis.
    The cache key is generated from the key_prefix and function arguments.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Generate a cache key based on function name, args, and kwargs
            # For simplicity, we'll just use args and kwargs as part of the key.
            # In a real app, you might want a more sophisticated key generation.
            cache_key_parts = [key_prefix, func.__name__]
            cache_key_parts.extend(map(str, args))
            for k, v in sorted(kwargs.items()):
                cache_key_parts.append(f"{k}={v}")
            
            cache_key = ":".join(cache_key_parts)

            # Try to get data from cache
            cached_data = redis_client.get(cache_key)
            if cached_data:
                print(f"Cache hit for {cache_key}")
                return json.loads(cached_data)

            print(f"Cache miss for {cache_key}. Executing function...")
            # If not in cache, execute the function
            result = func(*args, **kwargs)

            # Store the result in cache
            redis_client.setex(cache_key, timeout, json.dumps(result))
            return result
        return wrapper
    return decorator

